const purchases = $input.all();

const yahooMap = {
  'APC': 'APC.F', 'AMZ': 'AMZ.F', 'NVD': 'NVD.F', 'AP2': 'AP2.DE', 'MSF': 'MSF.F',
  'TL0': 'TL0.DE', 'TLO': 'TL0.DE', 'TKE': 'TKE.F', 'M4I': 'M4I.F', 'ABEA': 'ABEA.F',
  'CSPX': 'CSPX.AS', 'CNDX': 'CNDX.AS', '3ZU0': '3ZU0.F', '1170': '1170.F',
  '9D5': '9D5.F', 'GXG': 'GXG.F', 'BKSY': 'BKSY',
  'GOLD-ETFP': 'GOLD-EUR.PA',
  'AL2SI': 'AL2SI.PA', 'SU': 'SU.PA', 'ESE': 'ESE.PA',
  'EUEA': 'EUEA.AS', 'STEC': 'STEC.AS', 'ALRIB': 'ALRIB.PA',
  'SOI': 'SOI.PA', 'BTC': 'BTC-EUR'
};

// Passe 1 : somme nette par ticker (achats +qty, ventes -qty)
const netQty = {};
const nameMap = {};

for (const item of purchases) {
    const ticker = (item.json.ticker || '').toUpperCase().trim();
    const type = (item.json.assetType || '').toLowerCase();
    const qty = parseFloat(item.json.quantity) || 0;

    if (!ticker || ticker.startsWith('CASH-') ||
        ['cash', 'dividend', 'real estate', 'etf'].includes(type)) continue;

    netQty[ticker] = (netQty[ticker] || 0) + qty;
    if (!nameMap[ticker]) nameMap[ticker] = item.json.name || ticker;
}

// Passe 2 : garder uniquement les actifs encore détenus (qty nette > 0.01)
// Seuil 0.01 pour tolérer les arrondis de quantités fractionnelles (crypto)
const assets = [];
for (const [ticker, qty] of Object.entries(netQty)) {
    if (qty < 0.01) continue;
    const yahooTicker = yahooMap[ticker] || ticker;
    const name = nameMap[ticker];
    assets.push({ ticker: yahooTicker, name, keywords: `${name} ${ticker.split('.')[0]}` });
}

const allTickers = assets.map(a => a.ticker).join(',');
return assets.map(a => ({ json: { ...a, allTickers } }));

const articles = $('Aggregate').first().json.articles || [];
const asset = $('Loop Over Items').first().json;
const nameLower = (asset.name || '').toLowerCase();
const tickerBase = (asset.ticker || '').split('.')[0].toLowerCase();

// Garde uniquement les articles qui mentionnent l'actif par son nom ou ticker
const relevant = articles.filter(a => {
    const t = (a.title || '').toLowerCase();
    return t.includes(nameLower) || t.includes(tickerBase);
}).slice(0, 8);

return [{ 
  json: { 
    ticker: asset.ticker, 
    name: asset.name, 
    news: relevant.length > 0 ? relevant.map(a => `- ${a.title}`).join('\n') : null,
    hasNews: relevant.length > 0
  } 
}];

// 1. Texte Gemini
let texteGemini = $('Basic LLM Chain').first().json.text || "";
texteGemini = texteGemini.replace(/```markdown/gi, '').replace(/```/g, '').trim();
// Fallback si Gemini refuse ou retourne un texte trop court
if (!texteGemini || texteGemini.length < 60 || texteGemini.includes('je ne peux pas') || texteGemini.includes('il m\'est impossible')) {
    texteGemini = '🔷 *MARKET DIGEST – TOP 5 ACTUALITÉS*\n\n_Aucune actualité ciblée disponible aujourd\'hui._';
}

// 2. Noms dynamiques depuis Compile
const tickerNames = $('Compile').first().json.tickerNames || {};

// 3. Header portefeuille personnel depuis Firestore liveMetrics
let portfolioHeader = "";
try {
  const metrics = $('Firestore liveMetrics').first().json || {};
  const totalValue = parseFloat(metrics.totalValue) || 0;
  const totalReturn = parseFloat(metrics.totalReturn) || 0;
  const varToday = parseFloat(metrics.varToday) || 0;

  if (totalValue > 0) {
    const prevValue = totalValue - varToday;
    const todayPct = prevValue > 0 ? ((varToday / prevValue) * 100).toFixed(2) : "0.00";
    const totalInvested = totalValue - totalReturn;
    const totalPct = totalInvested > 0 ? ((totalReturn / totalInvested) * 100).toFixed(2) : "0.00";
    const todaySign = varToday >= 0 ? "+" : "";
    const totalSign = totalReturn >= 0 ? "+" : "";
    const todayEmoji = varToday >= 0 ? "🟢" : "🔴";
    const totalEmoji = totalReturn >= 0 ? "🟢" : "🔴";
    const valStr = totalValue.toLocaleString('fr-FR', {minimumFractionDigits: 2, maximumFractionDigits: 2});

    portfolioHeader = `👤 *TON PORTEFEUILLE*\n💼 Valeur : *${valStr} €*\n${todayEmoji} Aujourd'hui : *${todaySign}${varToday.toFixed(2)} €* (${todaySign}${todayPct}%)\n${totalEmoji} Performance totale : *${totalSign}${totalReturn.toFixed(2)} €* (${totalSign}${totalPct}%)\n\n——————————————————————\n\n`;
  }
} catch(e) {}

// 4. Tableau de bord des cours
const sparkData = $json;
let listeCours = [];

if (sparkData && sparkData.spark && sparkData.spark.result) {
  sparkData.spark.result.forEach(res => {
    const symbol = res.symbol;
    const nomPropre = tickerNames[symbol] || symbol.split('.')[0];
    if (res.response && res.response[0]) {
      const meta = res.response[0].meta;
      const price = meta.regularMarketPrice ? meta.regularMarketPrice.toFixed(2) : "N/A";
      const previousClose = meta.chartPreviousClose || meta.previousClose;
      const currency = meta.currency === "EUR" ? "€" : "$";
      let changePercent = 0;
      if (meta.regularMarketPrice && previousClose) {
        changePercent = ((meta.regularMarketPrice - previousClose) / previousClose) * 100;
      }
      listeCours.push({ nom: nomPropre, prix: price, devise: currency, perf: changePercent });
    }
  });
  listeCours.sort((a, b) => b.perf - a.perf);
}

let tableauCours = "📊 *TABLEAU DE BORD DES COURS*\n\n";
if (listeCours.length > 0) {
  listeCours.forEach(c => {
    const emoji = c.perf >= 0 ? "🟢" : "🔴";
    const sign = c.perf >= 0 ? "+" : "";
    tableauCours += `${emoji} *${c.nom}* : ${c.prix} ${c.devise} (${sign}${c.perf.toFixed(2)}%)\n`;
  });
} else {
  tableauCours += "⚠️ Impossible de charger le tableau des cours.\n";
}
tableauCours += "\n——————————————————————\n\n";

// 5. Actualités LLM
let actuAeree = texteGemini
  .replace(/\n•/g, '\n\n•')
  .replace(/\n🔹/g, '\n\n🔹')
  .trim();

return [{ json: { message: `${portfolioHeader}${tableauCours}${actuAeree}` } }];

const items = $input.all();
const tickerNames = {};
const tickerList = [];
items.forEach(i => {
    if (i.json.ticker) {
        tickerNames[i.json.ticker] = i.json.name;
        tickerList.push(i.json.ticker);
    }
});

// Seulement les actifs qui ont des articles pertinents
const withNews = items.filter(i => i.json.hasNews);
const resumeActus = withNews
  .map(i => `## ${i.json.name} (${i.json.ticker})\n${i.json.news}`)
  .join('\n\n');

return [{ json: { resume: resumeActus, hasNews: withNews.length > 0, allTickers: tickerList.join(','), tickerNames } }];

const text = $input.item.json.text;
const start = text.indexOf('{');
const end = text.lastIndexOf('}');
let clean = text.slice(start, end + 1);
clean = clean.replace(/[\u201C\u201D]/g, '\\"');
const data = JSON.parse(clean);

const stars = '⭐'.repeat(data.score);
const chatId = $('identifier l\'actif').first().json.chatId;

// Prix depuis Firestore snapshot (EUR)
const filterPos = $('Filter Position').first().json;
const lookupTicker = filterPos.firestoreTicker || filterPos.lookupTicker || filterPos.ticker;
let prix = 'N/A';
let currency = 'EUR';
let perf = '0.00';
let perfEmoji = '📊';
let perfSign = '';

try {
    const snapshot = $('Firestore Market Data').first().json;
    const prices = snapshot.prices || {};
    const priceData = prices[lookupTicker];
    if (priceData) {
        prix = parseFloat(priceData.price).toFixed(2);
        currency = priceData.currency || 'EUR';
        const dayChangePct = priceData.previousClose > 0 ? ((priceData.price - priceData.previousClose) / priceData.previousClose * 100) : (parseFloat(priceData.dayChangePct) || 0);
        perf = dayChangePct.toFixed(2);
        perfEmoji = dayChangePct >= 0 ? '📈' : '📉';
        perfSign = dayChangePct >= 0 ? '+' : '';
    }
} catch(e) {}

// Position personnelle depuis Filter Position
let positionText = '';
try {
    const pos = filterPos.positionSummary;
    if (pos && pos.hasPosition) {
        const currentPrice = parseFloat(prix);
        const currentValue = (currentPrice * pos.shares).toFixed(2);
        const invested = parseFloat(pos.totalInvested);
        const pnl = (currentPrice * pos.shares - invested).toFixed(2);
        const pnlPct = ((currentPrice * pos.shares / invested - 1) * 100).toFixed(2);
        const pnlEmoji = parseFloat(pnl) >= 0 ? '🟢' : '🔴';
        const pnlSign = parseFloat(pnl) >= 0 ? '+' : '';
        const pctSign = parseFloat(pnlPct) >= 0 ? '+' : '';
        positionText = `\n\n📦 *Ta position*\n🔢 ${pos.shares} @ ${pos.avgPrice} ${currency} moy\.\n💰 Valeur : ${currentValue} ${currency} \| Investi : ${invested.toFixed(2)} ${currency}\n${pnlEmoji} P&L : ${pnlSign}${pnl} ${currency} (${pctSign}${pnlPct}%)`;
    }
} catch(e) {}

const message = `${data.emoji} *${data.name}* (${data.ticker})\n💰 ${prix} ${currency} ${perfEmoji} ${perfSign}${perf}%\n${stars} Score : ${data.score}/5${positionText}\n\n${data.synthese}\n\n_${data.nb_articles} articles analysés_`;

return [{ json: { chatId, message } }];

const texte = $json.message.text.toLowerCase().trim();

if (texte === '/menu') {
  return [{ json: {
    isMenu: true, found: false, isDigest: false,
    chatId: $json.message.chat.id
  }}];
}

if (texte === '/news' || texte === '/digest' || texte === '📊 digest complet') {
  return [{ json: {
    found: false,
    isDigest: true,
    chatId: $json.message.chat.id,
    reply: '⏳ Analyse en cours pour tous tes actifs...'
  }}];
}

const cmdMap = {
  'ast': 'AST SpaceMobile',
  'blacksky': 'Blacksky',
  'amazon': 'Amazon',
  'apple': 'Apple',
  'bitcoin': 'Bitcoin',
  'tesla': 'Tesla',
  'nvidia': 'Nvidia',
  'alphabet': 'Alphabet',
  'taketwo': 'Take-Two',
  'ttwo': 'Take-Two',
  'schneider': 'Schneider Electric',
  'amat': 'Applied Materials',
  'arista': 'Arista Networks',
  'soitec': 'Soitec',
  'riber': 'Riber',
  'crsi': '2CRSI',
  'gold': 'Amundi Gold',
  'sp500': 'iShares S&P 500',
  'nasdaq': 'iShares NASDAQ 100',
  'stoxx50': 'iShares EURO STOXX 50',
  'stoxx600': 'iShares STOXX Europe 600 Tech',
  'bnp': 'BNP Paribas Easy S&P 500'
};

let texteSearch = texte;
if (texte.startsWith('/')) {
  const cmd = texte.slice(1).split('@')[0];
  if (cmdMap[cmd]) texteSearch = cmdMap[cmd].toLowerCase();
}

const assets = [
  { ticker: "ASTS",     name: "AST SpaceMobile",               keywords: "AST SpaceMobile ASTS stock" },
  { ticker: "BKSY",     name: "Blacksky",                      keywords: "Blacksky BKSY satellite" },
  { ticker: "AMZN",     name: "Amazon",                        keywords: "Amazon AMZN stock" },
  { ticker: "AAPL",     name: "Apple",                         keywords: "Apple AAPL stock" },
  { ticker: "BTC-USD",  name: "Bitcoin",                       keywords: "Bitcoin BTC crypto" },
  { ticker: "TSLA",     name: "Tesla",                         keywords: "Tesla TSLA stock" },
  { ticker: "NVDA",     name: "Nvidia",                        keywords: "Nvidia NVDA stock" },
  { ticker: "GOOGL",    name: "Alphabet",                      keywords: "Alphabet Google GOOGL" },
  { ticker: "TTWO",     name: "Take-Two",                      keywords: "Take-Two TTWO GTA" },
  { ticker: "SU.PA",    name: "Schneider Electric",            keywords: "Schneider Electric SU" },
  { ticker: "AMAT",     name: "Applied Materials",             keywords: "Applied Materials AMAT" },
  { ticker: "ANET",     name: "Arista Networks",               keywords: "Arista Networks ANET" },
  { ticker: "SOI.PA",   name: "Soitec",                        keywords: "Soitec SOI" },
  { ticker: "ALRIB.PA", name: "Riber",                         keywords: "Riber MBE bourse" },
  { ticker: "AL2SI.PA", name: "2CRSI",                         keywords: "2CRSI serveurs HPC" },
  { ticker: "GOLD.PA",  name: "Amundi Gold",                   keywords: "Amundi Gold ETF" },
  { ticker: "CSPX.AS",  name: "iShares S&P 500",               keywords: "iShares SP500 ETF" },
  { ticker: "CNDX.AS",  name: "iShares NASDAQ 100",            keywords: "iShares NASDAQ 100 ETF" },
  { ticker: "CS51.PA",  name: "iShares EURO STOXX 50",         keywords: "iShares EURO STOXX 50 ETF" },
  { ticker: "EXV3.DE",  name: "iShares STOXX Europe 600 Tech", keywords: "iShares STOXX Europe 600 Tech" },
  { ticker: "ESE.PA",   name: "BNP Paribas Easy S&P 500",      keywords: "BNP Paribas SP500 ETF" }
];

const asset = assets.find(a => {
  const cleanTicker = a.ticker.split('.')[0].toLowerCase();
  return texteSearch.includes(cleanTicker) || texteSearch.includes(a.name.toLowerCase());
});

if (!asset) {
  const botUsername = 'Fin_agent_tg_bot';
  const liste = assets.map(a =>
    `• [${a.name}](https://t.me/${botUsername}?text=${encodeURIComponent(a.name)})`
  ).join('\n');
  return [{ json: {
    found: false,
    isDigest: false,
    chatId: $json.message.chat.id,
    reply: `❌ Actif non reconnu\.\n\n📋 *Mes actifs suivis :*\n${liste}\n\n_Tape /news pour le digest complet_`
  }}];
}

return [{ json: {
  found: true,
  isDigest: false,
  chatId: $json.message.chat.id,
  ticker: asset.ticker,
  name: asset.name,
  keywords: asset.keywords
}}];

const askedTicker = $('identifier l\'actif').first().json.ticker;
const askedName = ($('identifier l\'actif').first().json.name || '').toLowerCase();
const allPurchases = $input.all();

const yahooMap = {
  'APC': 'APC.F', 'AMZ': 'AMZ.F', 'NVD': 'NVD.F', 'AP2': 'AP2.DE', 'MSF': 'MSF.F',
  'TL0': 'TL0.DE', 'TLO': 'TL0.DE', 'TKE': 'TKE.F', 'M4I': 'M4I.F', 'ABEA': 'ABEA.F',
  'CSPX': 'CSPX.AS', 'CNDX': 'CNDX.AS', '3ZU0': '3ZU0.F', '1170': '1170.F',
  '9D5': '9D5.F', 'GXG': 'GXG.F', 'BKSY': 'BKSY',
  'GOLD-ETFP': 'GOLD-EUR.PA',
  'AL2SI': 'AL2SI.PA', 'SU': 'SU.PA', 'ESE': 'ESE.PA',
  'EUEA': 'EUEA.AS', 'STEC': 'STEC.AS', 'ALRIB': 'ALRIB.PA',
  'SOI': 'SOI.PA', 'BTC': 'BTC-EUR'
};

const norm = t => t.toUpperCase().replace(/\.(PA|AS|DE|L|BR|MI|F)$/i, '');
const askedNorm = norm(askedTicker);

const netQty = {};
const nameMap = {};
for (const p of allPurchases) {
    const t = (p.json.ticker || '').toUpperCase().trim();
    const qty = parseFloat(p.json.quantity) || 0;
    if (!t) continue;
    netQty[t] = (netQty[t] || 0) + qty;
    if (!nameMap[t]) nameMap[t] = (p.json.name || t);
}

let firestoreTicker = null;
let assetName = null;

for (const [t, qty] of Object.entries(netQty)) {
    if (qty < 0.01) continue;
    if (t === askedTicker.toUpperCase() || norm(t) === askedNorm) {
        firestoreTicker = t;
        assetName = nameMap[t];
        break;
    }
    const fsName = (nameMap[t] || '').toLowerCase();
    if (askedName && fsName && (fsName.includes(askedName) || askedName.includes(fsName))) {
        firestoreTicker = t;
        assetName = nameMap[t];
        break;
    }
}

if (!firestoreTicker) {
    firestoreTicker = askedTicker;
    assetName = $('identifier l\'actif').first().json.name;
}

const lookupTicker = yahooMap[firestoreTicker] || firestoreTicker;

const relevant = allPurchases.filter(p => {
    const t = (p.json.ticker || '').toUpperCase();
    return t === firestoreTicker || norm(t) === norm(firestoreTicker);
});

let totalShares = 0;
let totalInvested = 0;

for (const p of relevant) {
    const qty = parseFloat(p.json.quantity) || 0;
    const price = parseFloat(p.json.price) || 0;
    if (qty > 0) {
        totalShares += qty;
        totalInvested += qty * price;
    }
}

totalShares = Math.round(totalShares * 100000) / 100000;
const avgPrice = totalShares > 0 ? (totalInvested / totalShares).toFixed(3) : "0";

return [{ json: {
    ticker: lookupTicker,
    lookupTicker,
    firestoreTicker,
    name: assetName,
    positionSummary: {
        shares: totalShares,
        avgPrice,
        totalInvested: totalInvested.toFixed(2),
        hasPosition: totalShares > 0
    }
}}];

const { isMenu, isDigest, found, chatId, name } = $json;
if (isMenu || (!isDigest && !found)) return [];
const text = isDigest
  ? '⏳ Analyse du portefeuille en cours...'
  : `⏳ Récupération des données pour *${name}*\.\.\.`;
return [{ json: { chatId, text } }];
